/** Auto-generated locale data for tutorials (21 EXTRA_LOCALES). Do not edit by hand unless intentional. */

export type ExtraLocaleTutorialArticle = {
  slug: string;
  title: string;
  intro: string;
  sections: Array<{
    id: string;
    title: string;
    blocks: Array<
      | { type: 'paragraph'; text: string }
      | { type: 'list'; items: string[] }
      | { type: 'image'; src?: string; alt: string; caption?: string }
      | { type: 'cta'; text: string; url: string }
    >;
  }>;
};

const GEO_IMAGE = "https://img.limaxai.com/aiweb/limaxai-2.webp";
const GEO_PROMPTS: string[] = [
  "A tea master pouring tea with traditional teapot, simple tea table",
  "A girl in hanfu holding red lantern, plain courtyard",
  "A calligrapher writing with brush on paper, minimal desk",
  "A child eating noodles with chopsticks, clean noodle shop",
  "A kung fu master in horse stance, empty training ground",
  "A musician playing guzheng, simple traditional room",
  "A vendor making sugar painting on stick, plain street stall",
  "A person practicing tai chi at sunrise, minimal park",
  "A craftsman folding paper crane, clean workspace",
  "A girl holding bamboo umbrella in rain, simple stone path",
];

function buildGeometryComicArticle(loc: string, g: typeof geometryComicExtraLocales.es): ExtraLocaleTutorialArticle {
  const items = g.labels.map((lab, i) => `${lab}: ${GEO_PROMPTS[i]}`);
  return {
    slug: 'midjourney-geometry-comic',
    title: g.title,
    intro: g.intro,
    sections: [
      { id: 'overview', title: g.overviewTitle, blocks: [{ type: 'paragraph', text: g.overviewText }] },
      { id: 'examples', title: g.examplesTitle, blocks: [{ type: 'paragraph', text: g.examplesIntro }, { type: 'list', items }] },
      { id: 'image', title: g.imageTitle, blocks: [{ type: 'image', src: GEO_IMAGE, alt: g.imageTitle, caption: g.imageCaption }] },
      { id: 'start', title: g.startTitle, blocks: [{ type: 'paragraph', text: g.startText }, { type: 'cta', text: g.ctaText, url: 'https://www.limaxai.com/' }] },
    ],
  };
}

