export function getNanobanana2EcommerceArticleForExtraLocale(loc: string): ExtraLocaleTutorialArticle | null {
  const c = (nanobanana2EcommerceExtraLocales as Record<string, NanobananaEcomExtraCopy>)[loc];
  if (!c) return null;
  return {
    slug: 'nanobanana2-ecommerce-detail',
    title: c.title,
    intro: c.intro,
    sections: [
      { id: 'prepare', title: c.prepareTitle, blocks: [{ type: 'list', items: [c.prepareItems[0], c.prepareItems[1]] }] },
      { id: 'step1', title: c.s1t, blocks: [{ type: 'paragraph', text: c.s1x }] },
      { id: 'step2', title: c.s2t, blocks: [{ type: 'paragraph', text: c.s2x }] },
      { id: 'step3', title: c.s3t, blocks: [{ type: 'paragraph', text: c.s3x }] },
      { id: 'why', title: c.whyT, blocks: [{ type: 'paragraph', text: c.whyx }] },
      { id: 'image', title: c.imgT, blocks: [{ type: 'image', src: NB_ECOM_IMG, alt: c.imgT, caption: c.imgC }] },
      { id: 'start', title: c.startT, blocks: [{ type: 'paragraph', text: c.startx }, { type: 'cta', text: c.cta, url: 'https://www.limaxai.com/' }] },
    ],
  };
}
